import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ editingTour, onSuccess, onClose }) => {
  const { user } = useAuth();
  const [formData, setFormData] = useState({ 
    title: '', location: '', price: '', status: 'Available', description: '' 
  });

  useEffect(() => {
    if (editingTour) {
      setFormData({ ...editingTour });
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const config = { headers: { Authorization: `Bearer ${user.token}` } };
      // 移除系統自動生成的欄位
      const { _id, __v, createdAt, updatedAt, ...payload } = formData;

      if (editingTour) {
        await axiosInstance.put(`/api/tours/${editingTour._id}`, payload, config);
      } else {
        await axiosInstance.post('/api/tours', payload, config);
      }
      alert('Success!');
      onSuccess();
    } catch (error) {
      alert('Error: ' + (error.response?.data?.message || 'Check connection'));
    }
  };

  const handleDelete = async () => {
    if (!window.confirm("Are you sure you want to delete this package?")) return;
    try {
      await axiosInstance.delete(`/api/tours/${editingTour._id}`, {
        headers: { Authorization: `Bearer ${user.token}` }
      });
      alert('Deleted!');
      onSuccess();
    } catch (error) {
      alert('Delete failed');
    }
  };

  return (
    <div className="flex flex-col min-h-screen bg-white">
      {/* 頂部 Header */}
      <div className="flex justify-between items-center p-5 border-b sticky top-0 bg-white">
        <button type="button" onClick={onClose} className="text-2xl text-gray-400">←</button>
        <h1 className="text-lg font-black text-gray-800">{editingTour ? 'Edit Tour' : 'Add Tour'}</h1>
        <button type="button" onClick={onClose} className="text-2xl text-gray-400">🏠</button>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6 flex-1 overflow-y-auto">
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2">Tour Title</label>
          <input type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} className="w-full p-4 bg-gray-50 border-none rounded-2xl" placeholder="Enter title" required />
        </div>

        {/* 上傳區塊 UI */}
        <div>
          <label className="block text-sm font-bold text-gray-700 mb-2">Upload cover picture</label>
          <div className="border-2 border-dashed border-gray-200 rounded-[30px] p-10 text-center bg-gray-50">
             <div className="text-4xl mb-2">☁️</div>
             <p className="font-bold text-gray-700 text-sm">Click to upload cover picture</p>
             <p className="text-[10px] text-gray-400 mt-1">PNG, JPG (MAX. 5MB)</p>
          </div>
        </div>

        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block text-sm font-bold text-gray-700 mb-2">Price (AUD)</label>
            <input type="number" value={formData.price} onChange={e => setFormData({...formData, price: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl" required />
          </div>
          <div className="flex-1">
            <label className="block text-sm font-bold text-gray-700 mb-2">Status</label>
            <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value})} className="w-full p-4 bg-gray-50 rounded-2xl appearance-none">
               <option value="Available">Available</option>
               <option value="Sold Out">Sold Out</option>
            </select>
          </div>
        </div>

        <button type="submit" className="w-full bg-emerald-500 text-white font-bold py-5 rounded-[20px] shadow-xl shadow-emerald-100 mt-4 active:scale-95 transition">
          {editingTour ? 'Update Package' : 'Submit'}
        </button>

        {/* 🔴 刪除按鈕只在編輯時出現 */}
        {editingTour && (
          <button type="button" onClick={handleDelete} className="w-full text-red-500 font-bold text-sm py-2 mt-2">
            Delete Tour Package
          </button>
        )}
      </form>
    </div>
  );
};

export default TourForm;
